164	            RBTDRM_COLOPHON_BARK,
165	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
166	        ]),
167	        RBTDRM_FIXTURE_HALLMARK_LIFECYCLE => Some(&[
168	            RBTDRM_COLOPHON_ORDAIN,
169	            RBTDRM_COLOPHON_ABJURE,
170	            RBTDRM_COLOPHON_REKON_HALLMARK,
171	            RBTDRM_COLOPHON_AUDIT_HALLMARKS,
172	        ]),
173	        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
174	            RBTDRM_COLOPHON_ORDAIN,
175	            RBTDRM_COLOPHON_ABJURE,
176	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
177	            RBTDRM_COLOPHON_VOUCH,
178	            RBTDRM_COLOPHON_TALLY,
179	        ]),
180	        RBTDRM_FIXTURE_ACCESS_PROBE => Some(&[RBTDRM_COLOPHON_ACCESS_PROBE]),
181	        RBTDRM_FIXTURE_ENROLLMENT_VALIDATION
182	        | RBTDRM_FIXTURE_REGIME_VALIDATION
183	        | RBTDRM_FIXTURE_REGIME_SMOKE
184	        | RBTDRM_FIXTURE_CALIBRANT_VERDICTS
185	        | RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST
186	        | RBTDRM_FIXTURE_CALIBRANT_PROGRESSING
187	        | RBTDRM_FIXTURE_CALIBRANT_SENTINEL => Some(&[]),
188	        RBTDRM_FIXTURE_DOCKERFILE_HYGIENE => Some(&[
189	            RBTDRM_COLOPHON_HYGIENE_CHECK,
190	            RBTDRM_COLOPHON_HYGIENE_CHECK_VESSEL,
191	        ]),
192	        RBTDRM_FIXTURE_PRISTINE_LIFECYCLE => Some(&[
193	            RBTDRM_COLOPHON_DEPOT_LEVY,
194	            RBTDRM_COLOPHON_DEPOT_LIST,
195	            RBTDRM_COLOPHON_DEPOT_UNMAKE,
196	            RBTDRM_COLOPHON_GOV_MANTLE,
197	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
198	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
199	            RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER,
200	            RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
201	            RBTDRM_COLOPHON_ACCESS_PROBE,
202	        ]),
203	        RBTDRM_FIXTURE_CANONICAL_ESTABLISH => Some(&[
204	            RBTDRM_COLOPHON_DEPOT_LEVY,
205	            RBTDRM_COLOPHON_DEPOT_LIST,
206	            RBTDRM_COLOPHON_GOV_MANTLE,
207	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
208	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
209	            RBTDRM_COLOPHON_ACCESS_PROBE,
210	        ]),
211	        RBTDRM_FIXTURE_ONBOARDING_SEQUENCE => Some(&[
212	            RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
213	            RBTDRM_COLOPHON_YOKE_RELIQUARY,
214	            RBTDRM_COLOPHON_ENSHRINE_VESSEL,
215	            RBTDRM_COLOPHON_ORDAIN,
216	            RBTDRM_COLOPHON_KLUDGE_SENTRY,
217	            RBTDRM_COLOPHON_KLUDGE_BOTTLE,
218	            RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE,
219	            RBTDRM_COLOPHON_SUMMON,
220	            RBTDRM_COLOPHON_PLUMB_FULL,
221	            RBTDRM_COLOPHON_PLUMB_COMPACT,
222	            RBTDRM_COLOPHON_REKON_HALLMARK,
223	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
224	            RBTDRM_COLOPHON_ABJURE,
225	        ]),
