238	            RBTDRM_COLOPHON_HW_DOCKER_CONTEXT,
239	            RBTDRM_COLOPHON_PAYOR_ESTABLISH,
240	            RBTDRM_COLOPHON_PAYOR_REFRESH,
241	            RBTDRM_COLOPHON_QUOTA_BUILD,
242	        ]),
243	        _ => None,
244	    }
245	}
246	
247	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
248	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
249	    let required = match rbtdrm_required_colophons(fixture) {
250	        Some(r) => r,
251	        None => {
252	            return Err(format!(
253	                "rbtd: unknown fixture '{}' — not registered in manifest",
254	                fixture
255	            ));
256	        }
257	    };
258	    for colophon in required {
259	        let found = manifest.split_whitespace().any(|token| token == *colophon);
260	        if !found {
261	            return Err(format!(
262	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
263	                colophon, fixture
264	            ));
265	        }
266	    }
267	    Ok(())
268	}
