286	// ── BURV fact file reading ───────────────────────────────────
287	
288	/// Read a fact file from a tabtarget's BURV output directory.
289	/// Fact files are single-line values written by tabtargets to BURD_OUTPUT_DIR,
290	/// which is BURV_OUTPUT_ROOT_DIR/current per BUK dispatch convention.
291	pub fn rbtdri_read_burv_fact(
292	    result: &rbtdri_InvokeResult,
293	    fact_name: &str,
294	) -> Result<String, String> {
295	    let path = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR).join(fact_name);
296	    let content = std::fs::read_to_string(&path)
297	        .map_err(|e| format!("rbtdri: cannot read fact '{}' from {}: {}", fact_name, path.display(), e))?;
298	    let trimmed = content.trim().to_string();
299	    if trimmed.is_empty() {
300	        return Err(format!("rbtdri: fact '{}' is empty in {}", fact_name, path.display()));
301	    }
302	    Ok(trimmed)
303	}
304	
305	/// Enumerate multi-fact files in a tabtarget's BURV output directory.
306	/// Multi-facts follow the convention `<root>.<ext>` written by buf_write_fact_multi;
307	/// returns the sorted list of roots whose files have the requested extension.
308	/// Returns an empty Vec if no matching files exist.
309	pub fn rbtdri_read_burv_facts_multi(
310	    result: &rbtdri_InvokeResult,
311	    extension: &str,
312	) -> Result<Vec<String>, String> {
313	    let dir = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
314	    let entries = std::fs::read_dir(&dir).map_err(|e| {
315	        format!(
316	            "rbtdri: cannot enumerate fact dir {}: {}",
317	            dir.display(),
318	            e
319	        )
320	    })?;
321	    let suffix = format!(".{}", extension);
322	    let mut roots: Vec<String> = entries
323	        .filter_map(|entry| entry.ok())
324	        .filter_map(|entry| entry.file_name().into_string().ok())
325	        .filter_map(|name| name.strip_suffix(&suffix).map(str::to_string))
326	        .collect();
327	    roots.sort();
328	    Ok(roots)
329	}
330	
331	// ── Ifrit verdict parsing ────────────────────────────────────
332	
333	/// Ifrit verdict wire protocol: ifrit prints exactly one line matching
334	/// `IFRIT_VERDICT: PASS` or `IFRIT_VERDICT: FAIL <detail>` to stdout.
335	/// Missing verdict line is always a failure — no silent pass-through.
336	pub fn rbtdri_parse_ifrit_verdict(stdout: &str, exit_code: i32) -> rbtdre_Verdict {
337	    for line in stdout.lines() {
338	        let trimmed = line.trim();
339	        if let Some(rest) = trimmed.strip_prefix("IFRIT_VERDICT:") {
340	            let rest = rest.trim();
341	            if rest.starts_with("PASS") {
342	                return rbtdre_Verdict::Pass;
343	            }
344	            if let Some(detail) = rest.strip_prefix("FAIL") {
345	                let detail = detail.trim();
346	                if detail.is_empty() {
347	                    return rbtdre_Verdict::Fail("ifrit reported failure".to_string());
348	                }
349	                return rbtdre_Verdict::Fail(detail.to_string());
350	            }
351	        }
352	    }
353	
354	    if exit_code == 0 {
355	        rbtdre_Verdict::Fail("ifrit exited 0 but no verdict line found".to_string())
356	    } else {
357	        rbtdre_Verdict::Fail(format!("ifrit exited {} with no verdict line", exit_code))
358	    }
359	}
360	
361	/// Invoke the ifrit binary inside a charged bottle via the bark tabtarget.
362	/// The attack selector argument tells ifrit which attack module to run.
363	/// Returns a test verdict based on ifrit's stdout verdict line and exit code.
364	pub fn rbtdri_invoke_ifrit(
365	    ctx: &mut rbtdri_Context,
366	    attack_selector: &str,
367	) -> Result<rbtdre_Verdict, String> {
368	    let result = rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRI_IFRIT_BINARY, attack_selector])?;
369	    Ok(rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code))
370	}
