#[test]
fn rbtdti_invoke_imprint_finds_correct_target() {
    let tmp = rbtdti_make_temp("invoke-imprint");
    let tt = rbtdti_make_tt_dir(&tmp);
    rbtdti_write_script(&tt, "rbw-cC.Charge.tadmor.sh", "echo 'tadmor'\n");
    rbtdti_write_script(&tt, "rbw-cC.Charge.srjcl.sh", "echo 'srjcl'\n");

